        System.out.println("Email sent for " + order.getId());
        return CompletableFuture.completedFuture(null);
    }

    @Async("taskExecutor")
    public void notifyWarehouse(Order order) {
        // Fire-and-forget warehouse notification
        System.out.printf("[%s] Notifying warehouse for %s%n",
            Thread.currentThread().getName(), order.getId());
    }
}
